import base64, os

os.makedirs(os.path.dirname(__file__), exist_ok=True)

logo7 = ""

logo8 = ""

import base64

# Salvar logo 7 (colorido)
with open(os.path.join(os.path.dirname(__file__), "logo-cor.png"), "wb") as f:
    f.write(base64.b64decode(logo7))

# Salvar logo 8 (branco/negativo)
with open(os.path.join(os.path.dirname(__file__), "logo-branco.png"), "wb") as f:
    f.write(base64.b64decode(logo8))

print("Logos salvos com sucesso.")
